import{_ as a,o as t,c as p,j as r,a as b,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"噬谎者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/噬谎者.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/噬谎者.md"}'),n={name:"4.资源分区/1.血统与训练/6.一次性血统/噬谎者.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"噬谎者",tabindex:"-1"},[b("噬谎者 "),r("a",{class:"header-anchor",href:"#噬谎者","aria-label":'Permalink to "噬谎者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="噬谎者-1" tabindex="-1">噬谎者 <a class="header-anchor" href="#噬谎者-1" aria-label="Permalink to &quot;噬谎者&quot;">​</a></h1><p>噬谎者<br> 一次性训练<br> S+9600<br> 编织谎言，操纵人心，一切都为其所用，潜藏在阴影中的布局者，拥有超绝智力与近乎狂妄的胆量</p><p>操纵人心<br> 你使用法术造成的所有伤害附带等量的控制点数（关键抵抗属性：决心、风度<br> 控制使人物屈服于特定的目标。被控制中的个体在对抗其控制目标的社交技能检定，和以意志抵抗其控制目标的特异或魔幻特殊能力时受到士气减值。<br> 抵抗不良状态：意志豁免。<br> 控制点数超过人物的决心或风度的较高者，则人物进入屈从状态。<br> 屈从状态的人物对该目标言听计从，除了明显送死或完全违反其道德观的指令之外，屈从状态的人物会接受所有命令。当接受到明显送死或完全违反道德观的命令时，屈从人物会获得一次对抗控制的机会，若这次对抗使得控制点数减到关键抵抗属性以下，人物会回归到控制状态。<br> 毁灭性后果：人物在精神上完全听信控制者的所有言论，即使这会伤害自己也不例外。），你造成的控制点数跳过命中步骤，且其还需再以意志豁免对抗一次伤害出目，若其对抗失败，则在其下个回合中的标准动作无法附带任何招式进行攻击，但仍可以正常进行普通攻击，这是一个A级心灵来源的效果</p><p>吞食黑金<br> 每花5000奖励点兑换为金钱（前提不为无限金钱），并将其完全花掉时，就可以再获得四百万等价于人民币购买力的金钱或换算成其他该世界观下的硬通货（包括但不限于黄金、魔法石等）</p><p>以下克上<br> 由你发起的一次赌局在对于一场影片内的NPC而言时，若其同意，则你可以选择将其拥有的，在本场影片内的地位或身份作为索取内容，并在赌局胜利时获取它。获取的地位或身份根据其拥有的地位或身份而浮动，但最高可以达到有关键经历的地位或身份，过去或者未来有改变世界现状的地位或身份。无论如何，在离开本场影片时失去它</p><p>还原推演<br> 近乎怪物般的思考方式和完美的空间想象能力带来了更多的可能性。在听到他人对一件事的完整描述时，可以如同身临其境一般“看到”整件事，并置身其中。带入这件事进行思考，对话，并经历整件事。若在这件事中，带入的那个角色受到了任何打击，自身也会如同受到了打击一般，完全的沉浸入其中对一件事进行还原并推演。通常情况下，对一件事的完全经历需要和那件事在现实中发生的时长幅度相同，在完整的经历过一次后，再次回顾整个事件只需要一半的时间。这件事距当前时间跨度不得超过二十年，经过时长不得超过一天，否则将因为信息的纷杂紊乱而无法还原推演</p><p>赌郎会员<br> 赌郎是一个巨大而神秘的地下组织，在多方势力间游走控制，并安插有搦手以监视一切动向。赌郎组织中仅有48个会员名额，因此，取得赌郎组织会员资格也是不少社会顶层人士所追求的目标。赌郎会员可以随时向无论是何身份的另一人发起赌局邀约，完全表明所有规则与赌注内容，只要其主观上表示同意，赌局视为成立。赌局的内容在规则上要求公平（可以由赌郎主持人规定，赌郎主持人一般视为st），赌局的结果要求提前确定（前提为对方拥有且可以给予），赌局时长最多不能超过一场影片，输掉赌局的一方需支付已确定的内容给胜利的一方，这可以是任何东西，也必须支付。这个效果视为一个B级心灵来源的胁迫效果，若在支付时无法支付，则由赌郎主持人决定支付其他事物以代替（包括生命）。因赌局而输掉的物品永久被对方获取，输掉的金钱以金钱换算形式将奖励点数兑换为金钱支付。若因一场赌局导致赌郎会员资格被对方夺走，则此训练中的所有能力即使仍拥有也无法再使用（特殊的，其他训练无法被作为赌注内容，但赌郎会员资格可以作为赌注，它不会在被夺走后为获取此资格的角色提供后续能力购买，也不会提供额外的属性点）。</p><p>Q：可被用于作为赌博支付的内容是否包括生命<br> A：对于发起赌局的一方而言，可以</p><p>Q：若因赌局而失去赌郎资格是否可以再次支付奖励点以购买赌郎会员资格<br> A：可以，原价购买</p><p>Q：如何判断一场赌局的规则是否公平<br> A：在规则层面不对任何一方有利，或由赌郎主持人决定</p><p>Q：若拥有足以抵抗胁迫等级的免疫效果，是否意味着可以白嫖<br> A：对于发起赌局的一方而言，即使有也是无效的。对于同意赌局的一方，若不想支付代价，最好的方式其实是不赌（笑）</p><p>Q：都有什么可以用作一次赌局的支付内容<br> A：对于能够以价值衡量的包括：物品（包括武器、防具、奇物、载具）、对方未拥有的技艺/称号、赌郎会员资格、金钱。其他内容需得到赌郎主持人认可</p><p>Q：因赌局失去的技艺/称号还可以再购买吗<br> A：可以</p><p>噬谎者下属称号：</p><p>赌郎主持人<br> A+4000<br> 前提：赌郎会员<br> 赌郎主持人，顾名思义，便是主持赌局的裁定者，不偏不倚，只遵守规则。赌郎主持人也可以向他人发起赌局邀约，亦可以主持一场赌局。赌郎主持人拥有极强的意志力与碾压般的武力和智力。在进行任何有关于智力、力量、敏捷为主属性检定的中，都可以一轮至多一次，重掷那次检定的结果，赌郎主持人可以任意选择两次结果中的一个进行结算<br> 在拥有赌郎主持人身份并经历6场影片后，赌郎组织便会对这一身份进行考核，此后便可以获得主持卍赌的权力<br> 所谓的卍赌，便是一种巨型的赌局方式，由参与双方抽签决定“刻”与“人”，抽到刻的一方决定卍赌时长，抽到人的一方决定卍赌参与人员，由赌郎主持人决定赌局规则与地点。在确认完毕后将开启一场以卍赌为主题的影片，由赌郎主持人监督主持整场赌局。卍赌在一场影片结束后只能进行一次，不能在一场正在进行的影片中举行卍赌。若赌郎主持人亲自作为进行赌博的一方下场，则由其他赌郎主持人代替主持这场卍赌。赌郎主持人在卍赌中若落败，则可以不支付那个代价，对方也不会获得对应的支付内容</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const A=a(n,[["render",o]]);export{f as __pageData,A as default};
